parameters.jsCode:
const prepareResult = $('Prepare Context').item.json;
const librarianResult = $('Librarian Check').item.json;

let librarianContext = '';
if (librarianResult.source === 'vector_index' && librarianResult.passages.length > 0) {
  librarianContext = '\n\n## Librarian — Relevant Citations\n';
  librarianResult.passages.forEach(p => {
    librarianContext += `\n- ${p.formatted}`;
  });
} else if (librarianResult.constitution_excerpt) {
  librarianContext = `\n\n## Librarian — Constitution Reference\n${librarianResult.constitution_excerpt}`;
  librarianContext += `\n\n*Note: ${librarianResult.note}*`;
}

return {
  task_id: prepareResult.task_id,
  trust_level: prepareResult.trust_level,
  librarian_result: librarianResult,
  messages: [
    { role: 'system', content: prepareResult.system_prompt + librarianContext },
    { role: 'user', content: prepareResult.user_message }
  ]
};

